function parseTitle(raw) {
  const t = (raw || '').replace(/\s*\|\s*LinkedIn\s*$/i, '').trim();
  const d = t.split(/\s+-\s+/);
  if (d.length >= 2) return { name: d[0].trim(), jobTitle: d[1].trim(), company: (d[2] || '').trim() };
  const p = t.split(/\s*\|\s*/);
  if (p.length >= 2) return { name: p[0].trim(), jobTitle: p[1].trim(), company: (p[2] || '').trim() };
  return { name: t, jobTitle: '', company: '' };
}
function scoreKDM(p) {
  const t = (p.job_title || '').toLowerCase();
  const all = t + ' ' + (p.snippet || '').toLowerCase();
  let s = 3;
  if (/\b(ceo|co-founder|cofounder|founder|pdg|cto|coo|cpo|chief|president|président)\b/.test(t)) s += 4;
  else if (/\b(vp|director|head of|responsable|directeur|managing)\b/.test(t)) s += 2;
  if (/\b(startup|saas|tech|ia|ai|b2b|scale|venture)\b/.test(all)) s += 2;
  if (/\b(france|paris|lyon|bordeaux|nantes|toulouse|français|française)\b/.test(all)) s += 1;
  return Math.min(s, 10);
}
const profiles = [];
for (const item of $input.all()) {
  for (const r of (item.json.organic || [])) {
    const url = (r.link || '').split('?')[0].split('#')[0];
    if (!url.includes('linkedin.com/in/') || url.endsWith('/in/')) continue;
    const { name, jobTitle, company } = parseTitle(r.title || '');
    if (!name) continue;
    profiles.push({ linkedin_url: url, name, job_title: jobTitle, company, snippet: (r.snippet || '').slice(0, 250), persona: 'A', persona_label: 'Key Decision Maker' });
  }
}
const seen = new Set();
const deduped = profiles.filter(p => { if (seen.has(p.linkedin_url)) return false; seen.add(p.linkedin_url); return true; });
return deduped.slice(0, 15).map(p => ({ json: { ...p, score: scoreKDM(p) } }));

