const profiles = $input.all().map(i => i.json).filter(p => !p._empty);
const fixedNote = $node["Config"].json.fixedNote;
const dateStr = new Date().toISOString().split('T')[0];
const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.seenUrls)) staticData.seenUrls = [];
const newUrls = profiles.map(p => p.linkedin_url).filter(Boolean);
staticData.seenUrls = [...staticData.seenUrls, ...newUrls];
if (staticData.seenUrls.length > 5000) staticData.seenUrls = staticData.seenUrls.slice(-5000);
const personaACount = profiles.filter(p => p.persona === 'A').length;
const personaBCount = profiles.filter(p => p.persona === 'B').length;
const avgScore = profiles.length > 0 ? (profiles.reduce((s, p) => s + (p.score || 0), 0) / profiles.length).toFixed(1) : '0.0';
const q = v => '"' + String(v || '').replace(/"/g, '""') + '"';
const sorted = [...profiles].sort((a, b) => (b.score || 0) - (a.score || 0));
const header = 'score,persona,nom,titre,entreprise,linkedin_url,note_connexion,batch_date';
const rows = sorted.map(p => [p.score || 0, p.persona === 'A' ? 'KDM' : 'Community', q(p.name), q(p.job_title), q(p.company), p.linkedin_url, q(fixedNote), dateStr].join(','));
const csv = header + '\n' + rows.join('\n');
const binary = await this.helpers.prepareBinaryData(Buffer.from(csv, 'utf-8'), 'prospects_' + dateStr + '.csv', 'text/csv');
return [{ json: { totalProfiles: profiles.length, personaACount, personaBCount, avgScore, dateStr }, binary: { attachment: binary } }];
